CLBConfig.RunR:
  if (Solver$Rank == 0) {
	vtks = 100
	solve = 5000
	check_electric = 100
	prev = 0
	Solver$Actions$Init()
	for (i in 1:solve) {
		Solver$Iter = i
		Solver$Actions$Iteration()  
		for (j in 1:2000000) 
		{
			Solver$Actions$Iter_Electric()
			if (j %% check_electric == 0) {
				diff = abs(prev - Solver$Quantities$ElectricField)
				criterion = sum(diff) / sum(abs(Solver$Quantities$ElectricField))
				if (criterion < 1e-7) {
					if (i %% vtks == 0) {cat("  iter:", i, "   Electric Iteration:", j, " Sum Difference:", criterion, "\n")}
					break
					}
				prev = Solver$Quantities$ElectricField
				}
		}

		if (i %% vtks == 0)  {Solver() }

		# if (i %% vtks == 0) {
		#   Solver$Actions$Iteration(globals = TRUE)  # Compute globals during iteration
		#   Solver$Actions$Iter_Electric()
		#   Solver()  # Trigger handlers like VTK
		#   cat("Iteration:", i, "SumPhiGas:", Solver$Globals$SumPhiGas, "\n")
		# } else {
		#   Solver$Actions$Iteration()  
		#   Solver$Actions$Iter_Electric()
		# }
	}
  }
